import{_ as t,o as i,c as s,a3 as e}from"./chunks/framework.CRbjHCyB.js";const k=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"catter/guide/quick-start.md","filePath":"en/catter/guide/quick-start.md"}'),n={name:"catter/guide/quick-start.md"};function l(r,a,p,o,h,d){return i(),s("div",null,[...a[0]||(a[0]=[e('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li><a href="https://pixi.sh" target="_blank" rel="noreferrer">pixi</a> for environment management</li><li>A C++ project with any build system (Make, Ninja, CMake, Meson, etc.)</li></ul><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Catter uses pixi for distribution. Install it with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pixi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> catter</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Catter is at v0.1.0 and under active development. The installation method may change in future releases.</p></div><h2 id="generate-a-compilation-database" tabindex="-1">Generate a Compilation Database <a class="header-anchor" href="#generate-a-compilation-database" aria-label="Permalink to &quot;Generate a Compilation Database&quot;">​</a></h2><p>Run your build command through catter to capture all compiler invocations:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> script::cdb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile_commands.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span></span></code></pre></div><p>This produces a <code>compile_commands.json</code> file in the current directory, ready for use with any language server or static analysis tool.</p><h2 id="command-format" tabindex="-1">Command Format <a class="header-anchor" href="#command-format" aria-label="Permalink to &quot;Command Format&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>catter [options] &lt;script&gt; [script-args] -- &lt;build-command&gt;</span></span></code></pre></div><p>Breaking down the CDB example:</p><table tabindex="0"><thead><tr><th>Part</th><th>Meaning</th></tr></thead><tbody><tr><td><code>script::cdb</code></td><td>Use the built-in CDB generation script (<code>script::</code> prefix selects built-in scripts)</td></tr><tr><td><code>-o compile_commands.json</code></td><td>Script-specific option: output file path</td></tr><tr><td><code>--</code></td><td>Separator between catter/script arguments and the build command</td></tr><tr><td><code>make</code></td><td>The actual build command to intercept</td></tr></tbody></table><h2 id="more-examples" tabindex="-1">More Examples <a class="header-anchor" href="#more-examples" aria-label="Permalink to &quot;More Examples&quot;">​</a></h2><h3 id="command-tree-visualization" tabindex="-1">Command tree visualization <a class="header-anchor" href="#command-tree-visualization" aria-label="Permalink to &quot;Command tree visualization&quot;">​</a></h3><p>View the captured build command DAG as an ASCII tree:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> script::cmd-tree</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span></span></code></pre></div><h3 id="using-with-cmake" tabindex="-1">Using with CMake <a class="header-anchor" href="#using-with-cmake" aria-label="Permalink to &quot;Using with CMake&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> script::cdb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile_commands.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><h3 id="custom-scripts" tabindex="-1">Custom scripts <a class="header-anchor" href="#custom-scripts" aria-label="Permalink to &quot;Custom scripts&quot;">​</a></h3><p>Use your own JavaScript script instead of a built-in one:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./my-script.js</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><h2 id="ide-support-for-script-development" tabindex="-1">IDE Support for Script Development <a class="header-anchor" href="#ide-support-for-script-development" aria-label="Permalink to &quot;IDE Support for Script Development&quot;">​</a></h2><p>Install the catter npm package to get TypeScript type definitions when writing custom scripts:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --save-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> catter</span></span></code></pre></div><p>This provides IDE autocompletion and type checking for the catter scripting API.</p>',28)])])}const u=t(n,[["render",l]]);export{k as __pageData,u as default};
